		public string resim(string uret, string mal, string texti, bool icerdemi)
		{
			string result = "";
			string text = "";
			string text2 = "";
			DataTable dataTable = this.xx.dtta(string.Concat(new string[]
			{
				"select tedarikid,edit,model from tedarik where malzeme='",
				mal,
				"' and model='",
				texti,
				"'"
			}), "");
			for (int i = 0; i < dataTable.Rows.Count; i++)
			{
				text = dataTable.Rows[i][0].ToString();
				text2 = dataTable.Rows[i][1].ToString();
			}
			try
			{
				string text3;
				if (icerdemi)
				{
					text3 = this.startuppath;
				}
				else
				{
					text3 = "http://www.as-cad.net/fcert";
				}
				Process.Start(string.Concat(new string[]
				{
					text3,
					"\\sertifika\\",
					mal,
					"\\",
					text,
					"\\",
					text2
				}));
			}
			catch (Exception ex)
			{
				MessageBox.Show("Hangi kapıdan gitceğimi söyleyeydin iyiydi.");
				StreamWriter streamWriter = new StreamWriter("C:\\SZGBKM\\asnhata.txt", true);
				streamWriter.WriteLine("Resimi bulamıyor veya resim yok;" + ex.Message);
				streamWriter.Close();
			}
			return result;
		}

