		public void dosyaget(string mlz, SearchLookUpEdit search)
		{
			bool flag = Convert.ToInt32(search.get_EditValue()) != 0;
			if (flag)
			{
				int ındexByKeyValue = search.get_Properties().GetIndexByKeyValue(search.get_EditValue());
				DataRow dataRow = (search.get_Properties().get_DataSource() as DataTable).Rows[ındexByKeyValue];
				this.tedid = dataRow["tedarikid"].ToString();
				this.mlzs = mlz.ToString();
				this.listView2.Items.Clear();
				string path = ".\\sertifika" + mlz + this.tedid.ToString();
				bool flag2 = Directory.Exists(path);
				if (!flag2)
				{
					Directory.CreateDirectory(path);
				}
				try
				{
					try
					{
						DirectoryInfo directoryInfo = new DirectoryInfo(path);
						DirectoryInfo[] directories = directoryInfo.GetDirectories();
						string[] files = Directory.GetFiles(path, "*.*");
						for (int i = 0; i < directories.Length; i++)
						{
							this.listView2.Items.Add(directories[i].ToString(), this._iconListManager.AddFileIcon(directories[i].FullName));
						}
						for (int j = 0; j < files.Length; j++)
						{
							this.listView2.Items.Add(Path.GetFileName(files[j].ToString()), this._iconListManager.AddFileIcon(files[j].ToString()));
						}
					}
					catch (Exception)
					{
					}
				}
				catch (Exception)
				{
				}
			}
			else
			{
				MessageBox.Show("Önce firma seçiniz");
			}
		}

