		public void hesaplama()
		{
			this.KapiAgirlik = Convert.ToDouble(this.OtoKapiAgr.Text);
			this.Byük = Convert.ToDouble(this.BeyanYuk.Text);
			this.tatk();
			bool flag = this.textBox37.Text == "";
			if (flag)
			{
				this.SusAgirlik = 0.0;
			}
			else
			{
				this.SusAgirlik = Convert.ToDouble(this.textBox37.Text);
			}
			this.v = double.Parse(this.BeyanHiz.Text);
			bool flag2 = this.v < 1.0;
			if (flag2)
			{
				this.tg = 10.0;
			}
			else
			{
				bool flag3 = this.v == 1.0;
				if (flag3)
				{
					this.tg = 7.0;
				}
				else
				{
					bool flag4 = this.v >= 1.6;
					if (flag4)
					{
						this.tg = 6.0;
					}
				}
			}
			bool flag5 = this.textBox51.Text == "";
			if (flag5)
			{
				this.ZAKat = 0.0;
			}
			else
			{
				this.ZAKat = Convert.ToDouble(this.textBox51.Text);
			}
			this.Ortalamakatim = Convert.ToDouble(this.DurakSayi.Value + decimal.One + Convert.ToInt32(this.textBox51.Text));
			bool flag6 = this.SeyirMesafesi.Text != "";
			if (flag6)
			{
				this.h = double.Parse(this.SeyirMesafesi.Text) / this.Ortalamakatim;
			}
			else
			{
				this.SeyirMesafesi.Text = "0";
			}
			bool flag7 = this.BeyanHiz.Text == "";
			if (flag7)
			{
				this.v = 0.0;
			}
			try
			{
				this.v = Convert.ToDouble(this.BeyanHiz.Text);
			}
			catch (Exception)
			{
				this.v = 0.0;
			}
			this.tv = Math.Round(this.h, 2) / this.v;
			this.ts = this.ta + this.tk + this.tg - this.tv;
			this.top = 0.0;
			double num = Convert.ToDouble(this.DurakSayi.Value);
			double num2 = Convert.ToDouble(this.BeyanKisi.Text);
			int num3 = 1;
			while ((double)num3 < num)
			{
				double x = (double)num3 / num;
				this.top += Math.Pow(x, num2);
				num3++;
			}
			double value = num - this.top;
			double x2 = (num - 1.0) / num;
			this.Se = num * (1.0 - Math.Pow(x2, num2));
			bool flag8 = this.KapiGen.Text == "";
			if (flag8)
			{
				this.y = 0;
			}
			else
			{
				this.y = int.Parse(this.KapiGen.Text);
			}
			bool flag9 = this.y < 1000;
			if (flag9)
			{
				this.tp = 2.2;
			}
			else
			{
				bool flag10 = this.y >= 1000;
				if (flag10)
				{
					this.tp = 2.0;
				}
			}
			bool flag11 = this.BinaKisiSay.Text == "";
			if (flag11)
			{
				this.b = 0.0;
			}
			else
			{
				this.b = (double)int.Parse(this.BinaKisiSay.Text);
			}
			bool flag12 = this.label41.Text == "";
			if (flag12)
			{
				this.n = 0.0;
			}
			else
			{
				this.n = double.Parse(this.label41.Text) / 100.0;
			}
			this.Be = this.b + this.n * this.b;
			double num4 = Math.Round(this.Se, 2);
			this.H = Math.Round(value, 2);
			bool flag13 = this.BeyanKisi.Text == "";
			if (flag13)
			{
				num2 = 0.0;
			}
