		private string griddendonen(string gelen)
		{
			string text = "";
			string result;
			for (int i = 0; i < this.gridView1.get_RowCount(); i++)
			{
				bool flag = this.gridView1.GetRowCellValue(i, "ParamName").ToString() == gelen;
				if (flag)
				{
					text = this.gridView1.GetRowCellValue(i, "ParamValue").ToString();
					result = text;
					return result;
				}
			}
			result = text;
			return result;
		}

