		public void WAltBul()
		{
			bool flag = this.comboBox35.get_SelectedIndex() != -1;
			if (flag)
			{
				MySqlConnection mySqlConnection = new MySqlConnection(this.xx.dtbase());
				mySqlConnection.Open();
				MySqlCommand mySqlCommand = new MySqlCommand(" select W from kiris where isim='" + this.comboBox35.Text + "'", mySqlConnection);
				MySqlDataReader mySqlDataReader = mySqlCommand.ExecuteReader();
				try
				{
					bool hasRows = mySqlDataReader.HasRows;
					if (hasRows)
					{
						while (mySqlDataReader.Read())
						{
							this.WAlt = Convert.ToDouble(mySqlDataReader[0].ToString());
						}
					}
				}
				catch (Exception)
				{
					MessageBox.Show("Hata Oluştu");
				}
				finally
				{
					mySqlConnection.Close();
				}
			}
		}

