		public void omega520bul1()
		{
			this.narintam = (int)Convert.ToInt16(Math.Floor(this.narinlik));
			bool flag = this.narintam >= 20 && this.narintam <= 50;
			if (flag)
			{
				this.omega520 = 8.24E-05 * Math.Pow(this.narinlik, 2.06) + 1.021;
			}
			else
			{
				bool flag2 = this.narintam >= 51 && this.narintam <= 70;
				if (flag2)
				{
					this.omega520 = 1.895E-05 * Math.Pow(this.narinlik, 2.41) + 1.05;
				}
				else
				{
					bool flag3 = this.narintam >= 71 && this.narintam <= 89;
					if (flag3)
					{
						this.omega520 = 2.447E-05 * Math.Pow(this.narinlik, 2.36) + 1.03;
					}
					else
					{
						bool flag4 = this.narintam >= 90 && this.narintam <= 250;
						if (flag4)
						{
							this.omega520 = 0.0002533 * Math.Pow(this.narinlik, 2.0);
						}
					}
				}
			}
		}

