		public void durum1()
		{
			this.Yq = 0.0;
			this.Xq = this.xderinlik / 8.0;
			this.Fx = this.darbe * this.gn * (this.Byük * this.Xq + (this.Kaküt + this.SusAgirlik + this.KapiAgirlik) * this.Xp) / (this.KRA * this.pamesafe);
			this.My = 3.0 * this.Fx * this.lk / 16.0;
			this.GerilmeY = this.My / this.Wy;
			this.Fy = this.darbe * this.gn * (this.Byük * this.Yq + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * this.Yp) / (this.KRA / 2.0 * this.pamesafe);
			this.Mx = 3.0 * this.Fy * this.lk / 16.0;
			this.GerilmeX = this.Mx / this.Wx;
			this.GerilmeM = this.GerilmeX + this.GerilmeY;
			Math.Round(this.GerilmeM, 2);
			this.durum1deg = Math.Round(this.GerilmeM, 2);
		}

		public void durum2()
		{
			this.Xq = 0.0;
			this.Yq = this.ygenislik / 8.0;
			this.Fx = this.darbe * this.gn * (this.Byük * this.Xq + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * this.Xp) / (this.KRA * this.pamesafe);
			this.My = 3.0 * this.Fx * this.lk / 16.0;
			this.GerilmeY = this.My / this.Wy;
			this.Fy = this.darbe * this.gn * (this.Byük * this.Yq + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * this.Yp) / (this.KRA / 2.0 * this.pamesafe);
			this.Mx = 3.0 * this.Fy * this.lk / 16.0;
			this.GerilmeX = this.Mx / this.Wx;
			this.GerilmeM = this.GerilmeX + this.GerilmeY;
			Math.Round(this.GerilmeM, 3);
			this.durum2deg = Math.Round(this.GerilmeM, 2);
		}

		public void NormalDurum1()
		{
			this.Xq = 0.0;
			this.Yq = 0.0;
			this.Xq = this.xderinlik / 8.0;
			this.Fx = 0.0;
			this.Fx = this.k2 * this.gn * (this.Byük * (this.Xq - this.Xs) + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * (this.Xp - this.Xs)) / (this.KRA * this.pamesafe);
			this.My = 0.0;
			this.My = 3.0 * this.Fx * this.lk / 16.0;
			this.GerilmeY = 0.0;
			this.GerilmeY = this.My / this.Wy;
			this.Fy = 0.0;
			this.Fy = this.k2 * this.gn * (this.Byük * (this.Yq - this.Ys) + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * (this.Yp - this.Ys)) / (this.KRA / 2.0 * this.pamesafe);
			this.Mx = 0.0;
			this.Mx = 3.0 * this.Fy * this.lk / 16.0;
			this.GerilmeX = 0.0;
			this.GerilmeX = this.Mx / this.Wx;
			this.GerilmeM1 = 0.0;
			this.GerilmeM1 = this.GerilmeX + this.GerilmeY;
			this.normaldurum1deg = Math.Round(this.GerilmeM1, 2);
		}

		public void NormalDurum2()
		{
			this.Xq = 0.0;
			this.Yq = this.ygenislik / 8.0;
			this.Fx = 0.0;
			this.Fx = this.k2 * this.gn * (this.Byük * (this.Xq - this.Xs) + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * (this.Xp - this.Xs)) / (this.KRA * this.pamesafe);
			this.My = 0.0;
			this.My = 3.0 * this.Fx * this.lk / 16.0;
			this.GerilmeY = 0.0;
			this.GerilmeY = this.My / this.Wy;
			this.Fy = 0.0;
			this.Fy = this.k2 * this.gn * (this.Byük * (this.Yq - this.Ys) + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * (this.Yp - this.Ys)) / (this.KRA / 2.0 * this.pamesafe);
			this.Mx = 0.0;
			this.Mx = 3.0 * this.Fy * this.lk / 16.0;
			this.GerilmeX = 0.0;
			this.GerilmeX = this.Mx / this.Wx;
			this.GerilmeM1 = 0.0;
			this.GerilmeM1 = this.GerilmeX + this.GerilmeY;
			this.normaldurum2deg = Math.Round(this.GerilmeM1, 2);
		}

		public void KarsiAgirlik()
		{
			this.Fx = 0.0;
			this.Fx = this.k2 * this.gn * (this.denge * this.Byük + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik)) * 0.1 * this.Dx / (this.KARA * this.Apamesafe);
			this.My = 0.0;
			this.My = 3.0 * this.Fx * this.lk / 16.0;
			this.GerilmeY = 0.0;
			this.GerilmeY = this.My / this.WyAgirlik;
			this.Fy = 0.0;
			this.Fy = this.k2 * this.gn * (this.denge * this.Byük + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik)) * 0.05 * this.Dy / (this.KARA / 2.0 * this.Apamesafe);
			this.Mx = 0.0;
			this.Mx = 3.0 * this.Fy * this.lk / 16.0;
			this.GerilmeX = 0.0;
			this.GerilmeX = this.Mx / this.WxAgirlik;
		}

