				mySqlConnection.Open();
				MySqlCommand mySqlCommand = new MySqlCommand("select fmin  from  halat where cap ='" + this.HalatCap.Text + "'", mySqlConnection);
				MySqlDataReader mySqlDataReader = mySqlCommand.ExecuteReader();
				try
				{
					bool hasRows = mySqlDataReader.HasRows;
					if (hasRows)
