		private void textBox21_KeyDown(object sender, KeyEventArgs e)
		{
			bool flag = e.KeyCode == Keys.Up;
			if (flag)
			{
				SendKeys.Send("+{TAB}");
			}
			bool flag2 = e.KeyCode == Keys.Down;
			if (flag2)
			{
				SendKeys.Send("{TAB}");
			}
			this.nonNumberEntered = false;
			bool flag3 = e.KeyCode == Keys.OemPeriod || e.KeyCode == Keys.Oemcomma;
			if (flag3)
			{
				this.nonNumberEntered = false;
			}
			else
			{
				bool flag4 = e.KeyCode < Keys.D0 || e.KeyCode > Keys.D9;
				if (flag4)
				{
					bool flag5 = e.KeyCode < Keys.NumPad0 || e.KeyCode > Keys.NumPad9;
					if (flag5)
					{
						bool flag6 = e.KeyCode != Keys.Back;
						if (flag6)
						{
							this.nonNumberEntered = true;
						}
					}
				}
			}
		}

