		public void koduazalt(SearchLookUpEdit s, string uretici, string model, string no, string belge, string nobo)
		{
			try
			{
				bool flag = s.Text != "";
				if (flag)
				{
					int ındexByKeyValue = s.get_Properties().GetIndexByKeyValue(s.get_EditValue());
					DataRow dataRow = (s.get_Properties().get_DataSource() as DataTable).Rows[ındexByKeyValue];
					this.findandreplace(this.appword, uretici, dataRow["uretici"].ToString());
					this.findandreplace(this.appword, model, dataRow["model"].ToString());
					this.findandreplace(this.appword, no, dataRow["serino"].ToString());
					this.findandreplace(this.appword, belge, dataRow["belgeveren"].ToString());
					this.findandreplace(this.appword, nobo, dataRow["nobo"].ToString());
				}
				else
				{
