			if (flag)
			{
				MySqlConnection mySqlConnection = new MySqlConnection(this.xx.dtbase());
				mySqlConnection.Open();
				MySqlCommand mySqlCommand = new MySqlCommand("select  s,Q,e,Lxx,wxx,imm,Lyy,wyy,iyy,g,c from ray where model='" + this.KabinRayStr.Text + "'", mySqlConnection);
				MySqlDataReader mySqlDataReader = mySqlCommand.ExecuteReader();
				try
				{
					bool hasRows = mySqlDataReader.HasRows;
					if (hasRows)
					{
						int num = 0;
						while (mySqlDataReader.Read())
						{
							bool flag2 = num == 0;
							if (flag2)
							{
								this.Bir = Convert.ToDouble(mySqlDataReader[0].ToString());
								this.Iki = Convert.ToDouble(mySqlDataReader[1].ToString());
								this.Uc = Convert.ToDouble(mySqlDataReader[2].ToString());
								this.Dort = Convert.ToDouble(mySqlDataReader[3].ToString());
								this.Bes = Convert.ToDouble(mySqlDataReader[4].ToString());
								this.Alti = Convert.ToDouble(mySqlDataReader[5].ToString());
								this.Yedi = Convert.ToDouble(mySqlDataReader[6].ToString());
								this.Sekiz = Convert.ToDouble(mySqlDataReader[7].ToString());
								this.Dokuz = Convert.ToDouble(mySqlDataReader[8].ToString());
								this.On = Convert.ToDouble(mySqlDataReader[9].ToString());
								this.OnBir = Convert.ToDouble(mySqlDataReader[10].ToString());
							}
						}
					}
				}
				catch (Exception)
				{
					MessageBox.Show("Lütfen Programı Yorucak Hamleler Yapmayınız");
