		public void hidOmege520bul()
		{
			this.hidnarintam = (double)Convert.ToInt16(Math.Floor(this.hidnarinlik));
			bool flag = this.hidnarintam >= 20.0 && this.hidnarintam <= 50.0;
			if (flag)
			{
				this.hidomega520 = 8.24E-05 * Math.Pow(this.hidnarinlik, 2.06) + 1.021;
			}
			else
			{
				bool flag2 = this.hidnarintam >= 51.0 && this.hidnarintam <= 70.0;
				if (flag2)
				{
					this.hidomega520 = 1.895E-05 * Math.Pow(this.hidnarinlik, 2.41) + 1.05;
				}
				else
				{
					bool flag3 = this.hidnarintam >= 71.0 && this.hidnarintam <= 89.0;
					if (flag3)
					{
						this.hidomega520 = 2.447E-05 * Math.Pow(this.hidnarinlik, 2.36) + 1.03;
					}
					else
					{
						bool flag4 = this.hidnarintam >= 90.0 && this.hidnarintam <= 250.0;
						if (flag4)
						{
							this.hidomega520 = 0.0002533 * Math.Pow(this.hidnarinlik, 2.0);
						}
					}
				}
			}
		}

		public void hidOmega370bul()
		{
			this.hidnarintam = (double)Convert.ToInt16(Math.Floor(this.hidnarinlik));
			bool flag = this.narintam >= 20 && this.narintam <= 60;
