		public void hidDurum1()
		{
			this.hidYq = 0.0;
			this.hidXq = this.xderinlik / 8.0;
			this.hidFx = this.darbe * this.gn * (this.Byük * this.hidXq + (this.Kaküt + this.SusAgirlik + this.KapiAgirlik) * this.Xp) / (this.HidKRA * this.pamesafe);
			this.hidMy = 3.0 * this.hidFx * this.lk / 16.0;
			this.hidGerilmeY = this.hidMy / this.HidWy;
			this.hidFy = this.darbe * this.gn * (this.Byük * this.hidYq + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * this.Yp) / (this.HidKRA / 2.0 * this.pamesafe);
			this.hidMx = 3.0 * this.hidFy * this.lk / 16.0;
			this.hidGerilmeX = this.hidMx / this.HidWx;
			this.hidGerilmeM = this.hidGerilmeX + this.hidGerilmeY;
			Math.Round(this.hidGerilmeM, 2);
			this.hiddurum1deg = Math.Round(this.hidGerilmeM, 2);
		}

