		public void hidNormaldurum1()
		{
			this.hidXq = 0.0;
			this.hidYq = 0.0;
			this.hidXq = this.xderinlik / 8.0;
			this.hidFx = 0.0;
			this.hidFx = this.k2 * this.gn * (this.Byük * (this.hidXq - this.Xs) + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * (this.Xp - this.Xs)) / (this.HidKRA * this.pamesafe);
			this.hidMy = 0.0;
			this.hidMy = 3.0 * this.hidFx * this.lk / 16.0;
			this.hidGerilmeY = 0.0;
			this.hidGerilmeY = this.hidMy / this.HidWy;
			this.hidFy = 0.0;
			this.hidFy = this.k2 * this.gn * (this.Byük * (this.hidYq - this.Ys) + (this.Kaküt + this.KapiAgirlik + this.SusAgirlik) * (this.Yp - this.Ys)) / (this.HidKRA / 2.0 * this.pamesafe);
			this.hidMx = 0.0;
			this.hidMx = 3.0 * this.hidFy * this.lk / 16.0;
			this.hidGerilmeX = 0.0;
			this.hidGerilmeX = this.hidMx / this.HidWx;
			this.hidGerilmeM1 = 0.0;
			this.hidGerilmeM1 = this.hidGerilmeX + this.hidGerilmeY;
			this.hidnormaldurum1deg = Math.Round(this.hidGerilmeM1, 2);
		}

