			this.hidnormaldurum2deg = Math.Round(this.hidGerilmeM1, 2);
		}

		public void Piston()
		{
			MySqlConnection mySqlConnection = new MySqlConnection(this.xx.dtbase());
			mySqlConnection.Open();
			MySqlCommand mySqlCommand = new MySqlCommand("select  tip from pistontip", mySqlConnection);
			MySqlDataReader mySqlDataReader = mySqlCommand.ExecuteReader();
			try
			{
				bool hasRows = mySqlDataReader.HasRows;
				if (hasRows)
				{
					while (mySqlDataReader.Read())
					{
						this.comboBox38.get_Properties().get_Items().Add(mySqlDataReader[0].ToString());
					}
				}
			}
			catch (Exception)
			{
				MessageBox.Show("Lütfen Programı Yorucak Hamleler Yapmayınız");
			}
			finally
			{
				mySqlConnection.Close();
			}
		}

