		public void hidcomboBox23bilgileri()
		{
			bool flag = this.KabinRayStr.get_SelectedIndex() != -1;
			if (flag)
			{
				MySqlConnection mySqlConnection = new MySqlConnection(this.xx.dtbase());
				mySqlConnection.Open();
				MySqlCommand mySqlCommand = new MySqlCommand("select  s,Q,e,Lxx, wxx,imm ,Lyy,wyy,iyy,g,c from ray where model ='" + this.comboBox20.Text + "'", mySqlConnection);
				MySqlDataReader mySqlDataReader = mySqlCommand.ExecuteReader();
				try
				{
					bool hasRows = mySqlDataReader.HasRows;
					if (hasRows)
					{
						int num = 0;
						while (mySqlDataReader.Read())
						{
							bool flag2 = num == 0;
							if (flag2)
							{
								this.hidBir = Convert.ToDouble(mySqlDataReader[0].ToString());
								this.hidIki = Convert.ToDouble(mySqlDataReader[1].ToString());
								this.hidUc = Convert.ToDouble(mySqlDataReader[2].ToString());
								this.hidDort = Convert.ToDouble(mySqlDataReader[3].ToString());
								this.hidBes = Convert.ToDouble(mySqlDataReader[4].ToString());
								this.hidAlti = Convert.ToDouble(mySqlDataReader[5].ToString());
								this.hidYedi = Convert.ToDouble(mySqlDataReader[6].ToString());
								this.hidSekiz = Convert.ToDouble(mySqlDataReader[7].ToString());
								this.hidDokuz = Convert.ToDouble(mySqlDataReader[8].ToString());
								this.hidOn = Convert.ToDouble(mySqlDataReader[9].ToString());
								this.hidOnBir = Convert.ToDouble(mySqlDataReader[10].ToString());
							}
						}
					}
				}
				catch (Exception)
				{
					MessageBox.Show("Lütfen Programı Yorucak Hamleler Yapmayınız");
				}
				finally
				{
					mySqlConnection.Close();
				}
			}
		}

