		private void textBox28_EditValueChanged(object sender, EventArgs e)
		{
			bool flag = this.KabinDer.Text == "";
			if (flag)
			{
				this.xderinlik = 0.0;
			}
			else
			{
				this.xderinlik = Convert.ToDouble(this.KabinDer.Text);
			}
			bool flag2 = this.KabinGen.Text == "";
			if (flag2)
			{
				this.ygenislik = 0.0;
			}
			else
			{
				this.ygenislik = Convert.ToDouble(this.KabinGen.Text);
			}
			this.Asansorm2 = this.ygenislik * this.xderinlik / 1000000.0;
			bool flag3 = this.Asansorm2 < 0.79;
			if (flag3)
			{
				this.enb = "4 'den Azdır!";
			}
			else
			{
				bool flag4 = this.Asansorm2 >= 0.79 && this.Asansorm2 < 0.98;
				if (flag4)
				{
					this.enb = "4'dür!";
				}
				else
				{
					bool flag5 = this.Asansorm2 >= 0.98 && this.Asansorm2 < 1.17;
					if (flag5)
					{
						this.enb = "5'dir!";
					}
					else
					{
						bool flag6 = this.Asansorm2 >= 1.17 && this.Asansorm2 < 1.45;
						if (flag6)
						{
							this.enb = "6'dır!";
						}
						else
						{
							bool flag7 = this.Asansorm2 >= 1.45 && this.Asansorm2 < 1.73;
							if (flag7)
							{
								this.enb = "8'dir!";
							}
							else
							{
								bool flag8 = this.Asansorm2 >= 1.73 && this.Asansorm2 < 2.15;
								if (flag8)
								{
									this.enb = "10'dur!";
								}
								else
								{
									bool flag9 = this.Asansorm2 >= 2.15 && this.Asansorm2 < 2.57;
									if (flag9)
									{
										this.enb = "13'dür!";
									}
									else
									{
										bool flag10 = this.Asansorm2 >= 2.57 && this.Asansorm2 < 3.24;
										if (flag10)
										{
											this.enb = "16'dır!";
										}
										else
										{
											bool flag11 = this.Asansorm2 >= 3.24 && this.Asansorm2 < 3.57;
											if (flag11)
											{
												this.enb = "21'dir!";
											}
											else
											{
												bool flag12 = this.Asansorm2 >= 3.57 && this.Asansorm2 < 4.0;
												if (flag12)
												{
													this.enb = "24'dür!";
												}
												else
												{
													this.enb = "24'den Fazladır!";
												}
											}
										}
									}
								}
							}
						}
					}
				}
			}
			this.label170.Text = "Taşınabilecek En Fazla İnsan Sayısı " + this.enb;
		}

